class Solution:
    def compress(self, chars: List[str]) -> int:
        w = i = 0
        while i < len(chars):
            ch = chars[i]; j = i
            while j < len(chars) and chars[j] == ch: j += 1
            chars[w] = ch; w += 1
            cnt = j - i
            if cnt > 1:
                for c in str(cnt): chars[w] = c; w += 1
            i = j
        return w

