class Solution {
public:
    int compress(vector<char>& c) {
        int w=0, i=0, n=c.size();
        while(i<n){
            char ch=c[i]; int j=i;
            while(j<n&&c[j]==ch) j++;
            c[w++]=ch; int cnt=j-i;
            if(cnt>1){ string s=to_string(cnt); for(char x:s) c[w++]=x; }
            i=j;
        }
        return w;
    }
};

