int compress(char* chars, int n) {
    int w=0,i=0;
    while(i<n){
        char ch=chars[i]; int j=i;
        while(j<n&&chars[j]==ch) j++;
        chars[w++]=ch; int cnt=j-i;
        if(cnt>1){
            char buf[12]; sprintf(buf,"%d",cnt);
            for(int k=0;buf[k];k++) chars[w++]=buf[k];
        }
        i=j;
    }
    return w;
}
